previewCss:
.darma-loader-darma-custom-638 {color: var(--loader-color, #2563eb);
  --loader-secondary-color: #38bdf8;
  --loader-bg: #ffffff;
   width: 80px;
   height: 16px;
   box-shadow: 0 15px 0 currentColor;
   position: relative;
   clip-path: polygon(0 -10px,100% -10px,100% 100%,50% calc(100% + 15px),0 100%);
}
.darma-loader-darma-custom-638:before, .darma-loader-darma-custom-638:after  {
  content: "";
   position: absolute;
   inset: auto 0 0;
   aspect-ratio: 1;
   background: radial-gradient(farthest-side,var(--loader-secondary-color, #38bdf8) 98%,#0000) bottom/14px 14px, radial-gradient(farthest-side,var(--loader-color, #2563eb) 98%,#0000) top /14px 14px, linear-gradient(currentColor 0 0) 50%/4px 95%;
   background-repeat: no-repeat;
   animation: darma-loader-darma-custom-638-l5 1.5s infinite linear;
   mix-blend-mode: lighten;
}
.darma-loader-darma-custom-638:after  {
  --d:-90deg;
}
@keyframes darma-loader-darma-custom-638-l5 {
  0% {transform:translateY(14px) rotate(calc( 0deg + var(--d,0deg)))}
100%{transform:translateY(14px) rotate(calc(-90deg + var(--d,0deg)))}
}

